def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + np.exp(-cap/10) * 60 + np.log1p(cap) * 15
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.sin(cap * 2)
            else:
                base_priority -= 60 * usage
            for i in range(1, 7):
                fluctuation += ((-1)**i) * np.cos(usage * np.pi * i * 0.9) * 25 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2 + 300 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.5)) * 30 / j
            if int(cap * 4) % 4 == 0:
                base_priority += 50 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3)**2.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.35:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 3)
                    if k == 11 and usage > 3.7:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                base_priority += 45 * np.cos(cap * 2.5)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2)**3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 30 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 18 / (m + 3)
                    if m == 16 and usage > 2.6:
                        fluctuation += 35
            if cap % 2.7 < 0.6:
                base_priority += 40 * np.sin(cap * 3.2)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1) ** 4
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 28 / n
                    if n % 4 == 3:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 14 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.7 < 0.4:
                base_priority += 32 * np.cos(cap * 2.3)
        elif 0.7 < usage <= 1:
            base_priority += 125 * (1 - usage)**1.5
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.05 * o:
                    fluctuation -= 10 * o
            if cap < 0.14:
                base_priority += np.sqrt(cap) * 290
            elif cap < 0.8:
                base_priority += np.log1p(cap * 22) * 40
            else:
                base_priority += (cap % 6) * 24
        elif 0.3 < usage <= 0.7:
            base_priority += 270 * (1 - usage) ** 2.2
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.2) * 12 / p
                if usage < 0.012 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.95:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        else:
            base_priority += 350 * (1 - usage) ** 3
            for q in range(1, 20):
                pwr = usage ** q
                fluctuation += (np.cos(pwr * np.pi / 7) - 0.3) * 10 / q
                if usage < 0.01 * q:
                    fluctuation -= 13 * q
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 340
            elif cap < 0.85:
                base_priority += np.log1p(cap * 28) * 48
            else:
                base_priority += (cap % 8) * 28
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 85
            if usage > 0.8:
                priority += 105
            elif usage < 0.1:
                priority -= 55
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 0.85:
            priority += 45
            if usage > 0.9:
                priority += 75
            elif usage < 0.15:
                priority -= 35
            for s in range(1, 7):
                if int(cap * 1400) % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 45
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 100
                for u in range(1, 6):
                    priority += u * 13
            else:
                priority += 35
        affinity = 0
        if int(cap * 3000) % 21 == 0:
            affinity += 18
        if int(cap * 1000) % 27 == 0:
            affinity -= 14
        if int(cap * 220) % 11 == 0:
            affinity += 16
        for v in range(1, 11):
            diff = abs(usage - v / 11)
            if diff < 0.015:
                affinity += 22 / v
            elif diff < 0.04:
                affinity += 14 / v
            else:
                affinity -= 5 / v
        for w in range(1, 10):
            mod_chk = int(cap * 1800) % (w + 10)
            if mod_chk == 0:
                affinity += w * 6
            elif mod_chk == 4:
                affinity -= w * 5
        for x in range(1, 6):
            mod_chk = int(usage * 1800) % (x + 7)
            if mod_chk == 0:
                affinity += 12 * x
            elif mod_chk == 4:
                affinity -= 9 * x
        priority += affinity
        if usage < 0.004:
            for y in range(1, 10):
                priority -= y * 12
        elif usage > 0.97:
            for z in range(1, 8):
                priority += z * 14
        if cap > 3.0:
            if cap % 1 < 0.07:
                priority += 50
            if (int(cap * 2750) % 29 == 0) and (usage > 0.75):
                priority += 70
            for aa in range(1, 7):
                if (int(cap * 650) % (aa + 12) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
